33	/**
34	 * @file utils/pybind11_glm.hpp
35	 * @brief Transparent conversion to and from Python for glm vector and matrix types.
36	 *
37	 * All converters for matrices assume col-major storage of glm, the default.
38	 * Things will likely break if non-default storage order is used.
39	 */
40	
41	template <typename T, uint32_t N>
42	struct type_caster<ngp::tvec<T, N>> {
43		using vector_type = ngp::tvec<T, N>;
44		using Scalar = T;
45		static constexpr std::size_t num_elements = N;
46	
47		bool load(handle src, bool)
48		{
49			array_t<Scalar> buf(src, true);
50			if (!buf.check())
51				return false;
52	
53			if (buf.ndim() == 1) // a 1-dimensional vector
54			{
55				if (buf.shape(0) != num_elements) {
56					return false; // not a 2-elements vector
57				}
58				if (buf.strides(0) != sizeof(Scalar))
59				{
60					std::cout << "An array with non-standard strides is given. Please pass a contiguous array." << std::endl;
61					return false;
62				}
63				value = vector_type(buf.mutable_data()); // make_vec* copies the data (unnecessarily)
64			}
65			else { // buf.ndim() != 1
66				return false;
67			}
68			return true;
69		}
70	
71		static handle cast(const vector_type& src, return_value_policy /* policy */, handle /* parent */)
72		{
73			return array(
74				num_elements,			// shape
75				src.data()		// data
76			).release();
77		}
78	
79		// Specifies the doc-string for the type in Python:
80		PYBIND11_TYPE_CASTER(vector_type, _("vec"));
81	};
82	
83	template <typename T, uint32_t N, uint32_t M>
84	struct type_caster<ngp::tmat<T, N, M>> {
85		using matrix_type = ngp::tmat<T, N, M>;
86		using Scalar = T;
87		static constexpr std::size_t num_rows = M;
88		static constexpr std::size_t num_cols = N;
89	
90		bool load(handle src, bool)
91		{
92			array_t<Scalar> buf(src, true);
93			if (!buf.check())
94				return false;
95	
96			if (buf.ndim() == 2) // a 2-dimensional matrix
97			{
98				if (buf.shape(0) != num_rows || buf.shape(1) != num_cols) {
99					return false; // not a 4x4 matrix
100				}
101				if (buf.strides(0) / sizeof(Scalar) != num_cols || buf.strides(1) != sizeof(Scalar))
102				{
103					std::cout << "An array with non-standard strides is given. Please pass a contiguous array." << std::endl;
104					return false;
105				}
106				// What we get from Python is laid out in row-major memory order, while GLM's
107				// storage is col-major, thus, we transpose.
108				value = ngp::transpose(matrix_type(buf.mutable_data())); // make_mat*() copies the data (unnecessarily)
109			}
110			else { // buf.ndim() != 2
111				return false;
112			}
113			return true;
114		}
115	
116		static handle cast(const matrix_type& src, return_value_policy /* policy */, handle /* parent */)
117		{
118			return array(
119				{ num_rows, num_cols }, // shape
120				{ sizeof(Scalar), sizeof(Scalar) * num_rows }, // strides - flip the row/col layout!
121				src.data()                            // data
122			).release();
123		}
124	
125		// Specifies the doc-string for the type in Python:
126		PYBIND11_TYPE_CASTER(matrix_type, _("mat"));
127	};
128	
129	NAMESPACE_END(detail)
130	NAMESPACE_END(pybind11)
131	
132	#if defined(_MSC_VER)
133	#pragma warning(pop)
